import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.BGHOrOyn.js";const d=JSON.parse('{"title":"Installing Companion Software Image","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/installing-companion-software-image.md","filePath":"robotics/installing-companion-software-image.md"}'),i={name:"robotics/installing-companion-software-image.md"};function r(s,e,l,h,p,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="installing-companion-software-image" tabindex="-1">Installing Companion Software Image <a class="header-anchor" href="#installing-companion-software-image" aria-label="Permalink to &quot;Installing Companion Software Image&quot;">​</a></h1><h2 id="installing-the-companion-computer-software-image" tabindex="-1">Installing the Companion Computer Software Image <a href="#installing-the-companion-computer-software-image" id="installing-the-companion-computer-software-image"></a> <a class="header-anchor" href="#installing-the-companion-computer-software-image" aria-label="Permalink to &quot;Installing the Companion Computer Software Image &lt;a href=&quot;#installing-the-companion-computer-software-image&quot; id=&quot;installing-the-companion-computer-software-image&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><blockquote><p>The current version of Companion is <strong>v0.0.31</strong>. If your system is out of date you can update by either installing a fresh image with the instructions below or connecting to Wi-Fi and performing a Software Update.</p></blockquote><p>The operating system and supporting software is installed by writing a pre-configured <code>.img</code> file to an SD Card which is then inserted into the Companion Computer (Raspberry Pi).</p><ol><li>Insert a microSD card with at least 4GB capacity into your topside computer with a card reader.</li><li>Download the Companion image <a href="https://s3.amazonaws.com/downloads.bluerobotics.com/Pi/stable/ardusub-raspbian.img.zip" target="_blank" rel="noreferrer">here</a> (updated 2021-Nov-30)</li><li>While the image downloads, download and install <a href="https://etcher.io/" target="_blank" rel="noreferrer">Etcher</a>. Make sure you select the correct download for your Operating System!</li><li>Open Etcher, select the image file (no need to extract beforehand) and your SD card, click &#39;Flash&#39; and wait for it to complete. </li><li>Eject the SD card, and insert it into the Raspberry Pi.</li></ol><h3 id="network-setup" tabindex="-1">Network Setup <a href="#network-setup" id="network-setup"></a> <a class="header-anchor" href="#network-setup" aria-label="Permalink to &quot;Network Setup &lt;a href=&quot;#network-setup&quot; id=&quot;network-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The <em>Companion Computer</em> is assigned a static IP address of 192.168.2.2, and it expects the surface computer to have an IP address of 192.168.2.1. The network configuration on the surface computer needs to be set up before it can communicate with the ROV. Choose your operating system below to display the appropriate network setup instructions.</p><h3 id="software-update" tabindex="-1">Software Update <a href="#software-update" id="software-update"></a> <a class="header-anchor" href="#software-update" aria-label="Permalink to &quot;Software Update &lt;a href=&quot;#software-update&quot; id=&quot;software-update&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Before proceeding, it is recommended to check for the latest updates for the Companion Computer.</p><p>To perform a companion software update:</p><ol><li>Plug a <em>fully charged</em> battery into the vehicle and connect the tether to the topside computer.</li><li>Navigate to <a href="http://192.168.2.2:2770/network" target="_blank" rel="noreferrer">192.168.2.2:2770/network</a> in an internet browser (Chrome, Edge, Firefox, etc.) and ensure that the vehicle has access to a WiFi network. If a webpage is not found at this address, verify the network settings are correct. Troubleshooting steps can be found here.</li><li>Navigate to <a href="http://192.168.2.2:2770/system" target="_blank" rel="noreferrer">192.168.2.2:2770/system</a>. Click the button that says &#39;Update Companion&#39;. If you do not see this button, then the companion software is up to date.</li><li>The update process will take between 5 and 20 minutes depending on the Internet connection speed. Wait for the update process to complete.</li><li>When it completes, refresh the browser. The Companion version should be updated, and the update available message should no longer appear.</li><li>If the update fails (usually due to a loss of internet connectivity), a warning will appear that the vehicle will reboot and to leave the battery plugged in. At this point, once, it is safe to either power down the vehicle or attempt the update again.</li></ol><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',14)])])}const m=t(i,[["render",r]]);export{d as __pageData,m as default};
